const QUIZ_BANK_P4 = {
  16: [
    // ── Module 16 · Steel Erection ── MC (1-35)
    { type: 'mc', q: "What is the minimum number of anchor bolts required per column under 29 CFR 1926 Subpart R?", options: ["2", "3", "4", "6"], a: 2, explain: "Subpart R requires a minimum of 4 anchor bolts per column to ensure structural stability during erection.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Who must design the anchor bolt pattern for steel columns?", options: ["Site foreman", "Steel erector", "Registered professional engineer", "OSHA inspector"], a: 2, explain: "Anchor bolt patterns must be designed by a registered professional engineer to ensure structural adequacy.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Under the two-bolt rule, how many bolts must be in place before the crane releases its load?", options: ["1", "2", "3", "4"], a: 1, explain: "The two-bolt rule requires that connectors install at least 2 bolts per connection before the crane releases the load.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "What is the maximum distance a Controlled Decking Zone (CDZ) may extend from the leading edge?", options: ["30 feet", "60 feet", "90 feet", "120 feet"], a: 2, explain: "A CDZ may extend no more than 90 feet from the leading edge of the decking operation.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "In a Controlled Decking Zone, work is limited to which decking bundles?", options: ["First bundle only", "First two bundles", "First three bundles", "All bundles"], a: 1, explain: "CDZ operations are limited to the first two bundles of decking from the leading edge.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "During initial erection, fall protection is required when workers are at or above:", options: ["6 feet or 2 stories (whichever is less)", "2 stories or 30 feet (whichever is less)", "15 feet or 1 story (whichever is less)", "10 feet at all times"], a: 1, explain: "During initial erection fall protection triggers at 2 stories or 30 feet, whichever is less. After that, the standard 6-foot rule applies.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "After initial erection is complete, the standard fall protection threshold for steel erection is:", options: ["2 feet", "4 feet", "6 feet", "10 feet"], a: 2, explain: "Once initial erection is done, the general construction fall protection rule of 6 feet applies.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Perimeter safety cables on open sides must be installed at which heights?", options: ["36 inches and 18 inches", "42 inches and 21 inches", "48 inches and 24 inches", "54 inches and 27 inches"], a: 1, explain: "Subpart R requires perimeter cables at 42 inches (top rail height) and 21 inches (mid-rail height).", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "What does 'plumbing up' mean in steel erection?", options: ["Installing plumbing pipes through steel members", "Making the structure vertical using guys and braces", "Checking anchor bolt torque values", "Installing perimeter cables"], a: 1, explain: "Plumbing up refers to the process of making the steel structure vertical (plumb) using guys, braces, and drift pins.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "When making a double connection, what is strictly prohibited?", options: ["Using impact wrenches", "Removing both bolts simultaneously", "Using drift pins", "Tightening bolts in sequence"], a: 1, explain: "Both bolts must never be removed at the same time during a double connection because this would leave the member unsupported.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Who has the authority to approve modifications to steel connections in the field?", options: ["The steel connector", "The general contractor superintendent", "A registered professional engineer", "The safety officer"], a: 2, explain: "Connections may only be modified with approval of a registered professional engineer — never by field personnel alone.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Shear connectors welded after decking installation are primarily a hazard because they:", options: ["Conduct electricity", "Create tripping hazards", "Block drainage", "Weaken the deck"], a: 1, explain: "Shear connectors protruding through the decking surface are recognized tripping hazards for workers walking on the deck.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "When placing bundles of decking on a structural member, workers must:", options: ["Stack all bundles in one location for efficiency", "Exceed rated capacity briefly only if supervised", "Spread the load evenly and not exceed capacity", "Always leave one bay empty"], a: 2, explain: "Deck bundles must be spread to distribute load evenly and must never exceed the rated capacity of the supporting member.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Which OSHA standard governs steel erection in construction?", options: ["29 CFR 1926 Subpart Q", "29 CFR 1926 Subpart R", "29 CFR 1926 Subpart S", "29 CFR 1910.217"], a: 1, explain: "Steel erection is governed by 29 CFR 1926 Subpart R — Steel Erection.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "The first two pieces of safety deck at each connection must be:", options: ["Inspected within 24 hours", "Secured immediately", "Left loose for adjustments", "Bolted with four fasteners each"], a: 1, explain: "The first two pieces of safety deck at each structural connection point must be secured immediately to prevent displacement.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "A steel connector must have at least how many bolts per connection before moving to the next connection?", options: ["1", "2", "3", "4"], a: 1, explain: "The two-bolt rule requires at least 2 bolts installed per connection before a connector can move on.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Which activity is most closely associated with establishing a Controlled Decking Zone?", options: ["Connecting structural columns", "Installing metal decking near the leading edge", "Welding shear studs", "Installing perimeter cables"], a: 1, explain: "A CDZ is a designated area used specifically for leading-edge metal decking operations where conventional fall protection is temporarily infeasible.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Fall protection for connectors during initial erection may be achieved by all EXCEPT:", options: ["Personal fall arrest systems", "Safety nets", "Positioning device systems", "Warning line systems alone"], a: 3, explain: "Warning line systems alone are not acceptable fall protection for connectors during steel erection; PFAS, nets, or positioning devices are required.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Before a steel erection company begins work, a site-specific erection plan must be developed by:", options: ["The owner", "A structural steel contractor with a licensed engineer's approval", "OSHA", "The general contractor's safety director"], a: 1, explain: "Subpart R requires the steel erector to develop a site-specific erection plan, often in coordination with a licensed engineer.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "What term describes the use of cables, guys, and braces to keep a steel frame plumb during construction?", options: ["Shoring", "Plumbing up", "Shaking out", "Flying", ], a: 1, explain: "Plumbing up is the process of guying, bracing, and aligning steel members to achieve a plumb, true structure.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Shakeout is the term for:", options: ["Removing anchor bolts", "Sorting and distributing steel members at the site", "Testing weld quality", "Inspecting perimeter cables"], a: 1, explain: "Shakeout refers to sorting, organizing, and distributing structural steel members on the jobsite prior to erection.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Which of the following is NOT a recognized method of fall protection during metal decking operations?", options: ["Safety net system", "Personal fall arrest system", "Controlled Decking Zone with guardrails", "Warning line system used alone in the CDZ"], a: 3, explain: "A warning line system alone does not constitute adequate fall protection; additional measures are required in the CDZ.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "When must the erection of a column begin after anchor bolts are set?", options: ["Immediately, to prevent corrosion", "Only after the concrete has achieved sufficient strength as specified by the engineer", "After a 24-hour waiting period required by OSHA", "Whenever the crane is available"], a: 1, explain: "Column erection must wait until concrete has achieved adequate strength as determined by the project engineer of record.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Which of the following best describes the purpose of perimeter safety cables in steel erection?", options: ["To support the weight of the decking", "To prevent workers from falling off open sides and edges", "To guide the crane load into position", "To mark the Controlled Decking Zone boundary"], a: 1, explain: "Perimeter safety cables act as a guardrail system to prevent worker falls on open sides and edges of the structure.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "What must happen before a controlled decking zone can be used in lieu of conventional fall protection?", options: ["Workers must sign a waiver", "The CDZ must be established with a written fall protection plan", "OSHA must approve it in advance", "The general contractor must agree"], a: 1, explain: "A written fall protection plan developed by a qualified person is required before using a CDZ.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "When raising a multi-story column, connectors working at height must have fall protection when the fall distance exceeds:", options: ["6 feet after initial erection phase", "15 feet at all times", "30 feet or 2 stories, whichever is less, during initial erection", "10 feet during any phase"], a: 2, explain: "During initial erection, fall protection is required at 2 stories or 30 feet (whichever is less); the 6-foot rule applies afterward.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Drift pins used during steel erection are primarily used for:", options: ["Measuring plumb accuracy", "Aligning bolt holes in connecting members", "Securing decking panels", "Lifting steel members"], a: 1, explain: "Drift pins are tapered pins driven into bolt holes to align connecting members so bolts can be inserted.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Which statement about steel column anchor bolts is correct?", options: ["They may be field-modified if the foreman approves", "They must be designed by a registered professional engineer", "OSHA allows a minimum of 2 per column for light columns", "They are optional if the column is braced"], a: 1, explain: "Anchor bolts must be designed by a registered professional engineer and a minimum of 4 are required per column.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Who is responsible for ensuring that steel is delivered in the proper sequence for erection?", options: ["OSHA compliance officer", "The steel fabricator and erector", "The concrete subcontractor", "The owner's project manager"], a: 1, explain: "The steel fabricator and erector coordinate delivery schedules so steel arrives in the correct sequence for safe, efficient erection.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Under Subpart R, which of the following is a requirement for multiple lift rigging (Christmas tree lifts)?", options: ["Maximum of 3 members per lift", "Maximum of 5 members per lift with a certified rigger", "Engineer must verify rigging plan; max 5 members", "No maximum number if the crane capacity allows"], a: 2, explain: "Multiple-lift rigging requires a qualified rigger, a written rigging plan, and a maximum of 5 members per lift.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Which term describes steel members being sorted, identified, and placed for crane pickup?", options: ["Plumbing up", "Double connection", "Shakeout", "Tiering"], a: 2, explain: "Shakeout is the process of sorting and staging steel members for crane pick.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "When a connector is working at a connection point with only one bolt, what must the connector do?", options: ["Immediately call the supervisor", "Install the second bolt before any crane load release", "Use a positioning device system while completing the connection", "Stop work and report to the safety officer"], a: 1, explain: "The two-bolt rule requires the second bolt to be installed before the crane releases the load — the connector must install both bolts.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "In steel erection, 'tiering' refers to:", options: ["Installing multiple layers of decking", "Erecting successive floors of a multi-story structure", "Stacking anchor bolt templates", "Installing perimeter cables at multiple heights"], a: 1, explain: "Tiering is the sequential erection of multiple floors (tiers) of a steel frame building.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "What is the primary purpose of a site-specific erection plan under Subpart R?", options: ["To satisfy union contract requirements", "To identify and control site-specific steel erection hazards", "To document OSHA permit approvals", "To schedule crane maintenance"], a: 1, explain: "The site-specific erection plan identifies and addresses the unique hazards of that particular steel erection project.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'mc', q: "Under 29 CFR 1926 Subpart R, decking holes and openings must be covered or protected:", options: ["Within 1 week of creation", "Immediately or as soon as the work creating the opening is complete", "Before the next shift begins", "Only if larger than 12 inches in diameter"], a: 1, explain: "Openings and holes in decking must be covered or otherwise protected immediately to prevent falls.", moduleRef: 16, moduleName: "Steel Erection" },

    // ── FIB (36-43)
    { type: 'fib', q: "Under 29 CFR 1926 Subpart R, a minimum of ___ anchor bolts are required per column.", answer: "4", accept: ["four"], explain: "Subpart R mandates a minimum of 4 anchor bolts per column for adequate structural support.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'fib', q: "The two-bolt rule requires connectors to have at least ___ bolts in place before the crane releases its load.", answer: "2", accept: ["two"], explain: "Two bolts per connection must be installed before the crane load is released.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'fib', q: "A Controlled Decking Zone may extend a maximum of ___ feet from the leading edge.", answer: "90", accept: ["ninety"], explain: "CDZs are limited to 90 feet from the leading edge of the decking operation.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'fib', q: "During initial erection of a multi-story structure, fall protection is required at ___ stories or 30 feet, whichever is less.", answer: "2", accept: ["two"], explain: "The trigger for fall protection during initial erection is 2 stories or 30 feet, whichever occurs first.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'fib', q: "Perimeter safety cables must be installed at 42 inches and ___ inches on open sides.", answer: "21", accept: ["twenty-one"], explain: "Subpart R requires cables at 42 inches (top) and 21 inches (mid-rail) on open perimeters.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'fib', q: "The process of making a steel structure vertical using guys and braces is called ___.", answer: "plumbing up", accept: ["plumb up", "plumbing-up"], explain: "Plumbing up is the steel erection process of making the frame plumb (vertical).", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'fib', q: "Steel column anchor bolt patterns must be designed by a registered professional ___.", answer: "engineer", accept: ["PE", "structural engineer"], explain: "Only a registered professional engineer may design anchor bolt patterns for steel columns.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'fib', q: "The CDZ is limited to work on the first ___ bundles of decking from the leading edge.", answer: "two", accept: ["2"], explain: "Only the first two decking bundles from the leading edge may be handled within the CDZ.", moduleRef: 16, moduleName: "Steel Erection" },

    // ── SA (44-50)
    { type: 'sa', q: "Which of the following are requirements under 29 CFR 1926 Subpart R for column anchor bolts? (Select all that apply)", options: ["Minimum of 4 bolts per column", "Designed by a registered professional engineer", "May be field-modified by the foreman", "Must not be bent or damaged before erection"], answers: [0, 1, 3], explain: "Anchor bolts must number at least 4, be engineer-designed, and must be in good condition. Field modification without engineer approval is prohibited.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'sa', q: "Which of the following are acceptable methods of fall protection during metal decking operations? (Select all that apply)", options: ["Personal fall arrest system", "Safety net system", "Warning line system used alone", "Controlled Decking Zone with a fall protection plan"], answers: [0, 1, 3], explain: "PFAS, safety nets, and a properly established CDZ are acceptable. A warning line system alone is not sufficient.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'sa', q: "Which of the following actions are prohibited during a double connection in steel erection? (Select all that apply)", options: ["Removing both bolts at the same time", "Using drift pins for alignment", "Making the connection without engineer-approved plans", "Installing more than two bolts"], answers: [0, 2], explain: "Both bolts must never be removed simultaneously, and connections must not be modified without engineer approval.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'sa', q: "Which of the following are true regarding the Controlled Decking Zone (CDZ)? (Select all that apply)", options: ["It may extend up to 90 feet from the leading edge", "It requires a written fall protection plan", "Any number of decking bundles may be handled in the CDZ", "It is limited to the first two bundles from the leading edge"], answers: [0, 1, 3], explain: "A CDZ is limited to 90 feet, requires a written fall protection plan, and work is limited to the first two decking bundles.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'sa', q: "Which of the following are requirements for multiple-lift rigging (Christmas tree lifts) under Subpart R? (Select all that apply)", options: ["A qualified rigger must supervise", "A written rigging plan is required", "A maximum of 5 members per lift", "All members must be the same size and weight"], answers: [0, 1, 2], explain: "Multiple lifts require a qualified rigger, written rigging plan, and a cap of 5 members. Members need not be identical.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'sa', q: "Which of the following create tripping or fall hazards on steel decking? (Select all that apply)", options: ["Shear connectors protruding above the deck surface", "Uncovered deck holes and openings", "Properly secured decking panels", "Loose tools and materials left on the deck"], answers: [0, 1, 3], explain: "Protruding shear connectors, uncovered openings, and loose materials are all recognized tripping/fall hazards on decking.", moduleRef: 16, moduleName: "Steel Erection" },
    { type: 'sa', q: "Which of the following are required elements of a site-specific steel erection plan? (Select all that apply)", options: ["Identification of site-specific hazards", "Sequence of erection and crane picks", "OSHA's written concurrence", "Fall protection methods to be used"], answers: [0, 1, 3], explain: "The erection plan must address site hazards, erection sequence, and fall protection methods. OSHA's advance concurrence is not required.", moduleRef: 16, moduleName: "Steel Erection" },
  ],

  17: [
    // ── Module 17 · Fire Protection & Prevention ── MC (1-35)
    { type: 'mc', q: "Which fire class involves ordinary combustibles such as wood and paper?", options: ["Class B", "Class C", "Class A", "Class D"], a: 2, explain: "Class A fires involve ordinary combustibles such as wood, paper, cloth, and trash.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Which fire class covers flammable liquids and gases?", options: ["Class A", "Class B", "Class C", "Class K"], a: 1, explain: "Class B fires involve flammable liquids and gases such as gasoline, oil, and propane.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Class C fires involve:", options: ["Combustible metals", "Cooking oils and fats", "Electrical equipment", "Ordinary combustibles"], a: 2, explain: "Class C fires involve energized electrical equipment.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "What does the acronym PASS stand for when using a fire extinguisher?", options: ["Pull, Aim, Squeeze, Sweep", "Push, Aim, Spray, Sweep", "Pull, Activate, Squeeze, Spray", "Point, Aim, Squeeze, Spread"], a: 0, explain: "PASS: Pull the pin, Aim at the base of the fire, Squeeze the handle, Sweep side to side.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "For Class A fires, the maximum travel distance to a fire extinguisher is:", options: ["50 feet", "75 feet", "100 feet", "25 feet"], a: 1, explain: "OSHA requires extinguishers for Class A hazards to be within 75 feet of travel distance.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "For Class B and C fires, the maximum travel distance to a fire extinguisher is:", options: ["75 feet", "50 feet", "100 feet", "25 feet"], a: 1, explain: "Extinguishers for Class B and C hazards must be within 50 feet of travel distance.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Which type of fire extinguisher is most commonly used on construction sites?", options: ["CO2", "Water", "ABC dry chemical", "Class D dry powder"], a: 2, explain: "ABC dry chemical extinguishers are the most common on construction sites because they cover the three most frequent fire classes.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Why is a CO2 extinguisher preferred for electrical fires?", options: ["It is the cheapest option", "It displaces oxygen and leaves no residue", "It is the most powerful type", "It is rated for Class A fires"], a: 1, explain: "CO2 extinguishes by displacing oxygen and leaves no corrosive or conductive residue on electrical equipment.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "A flammable liquid is defined as having a flash point of:", options: ["Less than 100°F", "100–200°F", "Greater than 200°F", "Greater than 140°F"], a: 0, explain: "Flammable liquids have a flash point below 100°F; combustible liquids have flash points between 100°F and 200°F.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "A combustible liquid has a flash point in the range of:", options: ["Below 100°F", "100°F to 200°F", "Above 200°F", "Below 73°F"], a: 1, explain: "Combustible liquids are defined by flash points between 100°F and 200°F.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "When storing more than 25 gallons of flammable liquids, they must be kept in:", options: ["An approved container only", "A listed storage room or cabinet", "An outdoor area away from the building", "Labeled 5-gallon metal cans"], a: 1, explain: "Quantities over 25 gallons of flammable liquids require storage in a listed/approved storage room or storage cabinet.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Quantities of flammable liquid exceeding ___ gallons must be stored in a listed container.", options: ["5 gallons", "10 gallons", "15 gallons", "25 gallons"], a: 1, explain: "More than 10 gallons of flammable liquid must be stored in a listed (approved) container.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "A hot work permit is required when:", options: ["Workers handle flammable liquids near exits", "Welding or cutting is performed in fire-prone areas", "Using extension cords on construction sites", "Heating materials with electric heat guns"], a: 1, explain: "Hot work permits are required for welding, cutting, or other spark-producing operations in areas with fire risk.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "A fire watch must be maintained for at least how long after hot work is complete?", options: ["15 minutes", "30 minutes minimum (up to 60 minutes per conditions)", "1 hour at minimum", "Until the next shift begins"], a: 1, explain: "OSHA and NFPA require a fire watch for a minimum of 30 minutes (and up to 60 minutes depending on conditions) after hot work ends.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "How often must portable fire extinguishers be inspected on construction sites?", options: ["Weekly", "Monthly", "Quarterly", "Annually"], a: 1, explain: "OSHA requires monthly inspections of portable fire extinguishers on construction sites.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "In addition to monthly inspection, fire extinguishers must receive annual:", options: ["Pressure testing", "Maintenance (servicing)", "Replacement of the agent", "OSHA certification"], a: 1, explain: "Annual maintenance (professional servicing) is required in addition to monthly inspections.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Smoking is prohibited within ___ feet of flammable materials on a construction site.", options: ["10 feet", "20 feet", "25 feet", "50 feet"], a: 1, explain: "OSHA requires a no-smoking zone of at least 20 feet from flammable materials.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Temporary heating equipment must maintain a clearance of ___ feet from combustibles.", options: ["1 foot", "2 feet", "3 feet", "5 feet"], a: 2, explain: "Temporary heaters must be kept at least 3 feet away from combustible materials to prevent ignition.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "The OSHA construction standard governing fire protection and prevention is:", options: ["29 CFR 1926 Subpart E", "29 CFR 1926 Subpart F", "29 CFR 1926 Subpart J", "29 CFR 1926 Subpart Q"], a: 1, explain: "Fire protection and prevention is governed by 29 CFR 1926 Subpart F.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "When aiming a fire extinguisher, where should the discharge be directed?", options: ["At the top of the flames", "At the center of the fire", "At the base of the fire", "At the smoke above the fire"], a: 2, explain: "The PASS technique specifies aiming at the base of the fire where the fuel source is located.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Class D extinguishers are specifically designed for:", options: ["Grease and cooking fires", "Combustible metals such as magnesium and titanium", "Electrical equipment", "Ordinary combustibles"], a: 1, explain: "Class D dry powder extinguishers are designed for combustible metal fires (magnesium, titanium, sodium, etc.).", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Class K extinguishers are used for:", options: ["Kitchen cooking oil fires", "Chemical laboratory fires", "Combustible metal fires", "Flammable gas fires"], a: 0, explain: "Class K extinguishers are designed for cooking oil and fat fires in commercial cooking equipment.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Who must perform a fire watch during hot work?", options: ["Any available worker", "A trained person designated for that purpose", "The welder themselves", "A licensed fire inspector"], a: 1, explain: "A fire watch must be performed by a trained, designated individual — not just any available worker.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "What is the first step in the PASS technique for using a fire extinguisher?", options: ["Aim at the base of the fire", "Squeeze the handle", "Pull the safety pin", "Sweep side to side"], a: 2, explain: "The first step is to Pull the pin (safety pin) from the extinguisher handle.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Which of the following is an example of a Class A combustible?", options: ["Gasoline", "Electrical panel", "Wood framing", "Magnesium shavings"], a: 2, explain: "Wood is a classic Class A ordinary combustible material.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Flammable liquids should be dispensed using:", options: ["Any open container", "Approved safety cans with self-closing lids", "Standard plastic buckets", "Open-top metal drums"], a: 1, explain: "OSHA requires flammable liquids to be dispensed from approved safety cans with self-closing lids and flame arrestors.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "What should a fire watch person do if a fire is discovered after hot work?", options: ["Wait to see if it grows before acting", "Immediately activate the alarm and use extinguisher if safe", "Wait for the welder to return", "Douse with water from any available source"], a: 1, explain: "The fire watch must immediately sound the alarm and attempt to extinguish the fire only if it is safe to do so.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Which extinguishing agent is NOT appropriate for use on an energized electrical fire?", options: ["CO2", "Dry chemical", "Halon substitute", "Water"], a: 3, explain: "Water conducts electricity and must never be used on energized electrical fires due to electrocution risk.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "What information must be documented on a hot work permit?", options: ["Worker's home address", "Location, type of work, time period, and fire precautions", "Insurance policy number", "Crane serial number"], a: 1, explain: "A hot work permit must document the work location, type of hot work, authorized time period, and required fire precautions.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Combustible waste materials on a construction site should be:", options: ["Stored in any convenient location", "Removed at the end of each workday or placed in covered metal containers", "Piled near the exit for easy removal", "Kept moist to prevent ignition"], a: 1, explain: "Combustible waste must be removed daily or stored in covered metal containers to reduce fire risk.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Which of the following is NOT a recognized fire class under NFPA/OSHA standards?", options: ["Class A", "Class E", "Class B", "Class K"], a: 1, explain: "There is no Class E fire classification. The recognized classes are A, B, C, D, and K.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "The purpose of a hot work permit system is to:", options: ["Replace the need for fire extinguishers", "Ensure fire hazards are identified and controlled before work begins", "Satisfy union contract requirements", "Speed up the welding process"], a: 1, explain: "A hot work permit ensures that hazards are identified and appropriate controls (fire watch, extinguishers, cleared combustibles) are in place before hot work starts.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Portable fire extinguishers on construction sites must be located so they are:", options: ["Hidden in a locked cabinet for security", "Visible and accessible without moving obstacles", "Stored in the job trailer", "Mounted above 5 feet for safety"], a: 1, explain: "Extinguishers must be clearly visible and readily accessible at all times without requiring workers to move equipment or materials.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "If a fire extinguisher has been used even partially, what must happen?", options: ["It can be reused until completely empty", "It must be recharged or replaced before being returned to service", "It must be discarded immediately", "It only needs to be tagged as 'partially used'"], a: 1, explain: "Any extinguisher that has been used must be recharged or replaced before being put back into service, regardless of how much agent remains.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'mc', q: "Which of the following best describes the flash point of a liquid?", options: ["The temperature at which it spontaneously ignites", "The lowest temperature at which it emits enough vapor to ignite near a flame", "The highest temperature it can reach before boiling", "The temperature at which it is classified as combustible"], a: 1, explain: "Flash point is the minimum temperature at which a liquid produces sufficient vapor to briefly ignite when exposed to an ignition source.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },

    // ── FIB (36-43)
    { type: 'fib', q: "The acronym PASS stands for Pull, Aim, Squeeze, and ___.", answer: "Sweep", accept: ["sweep side to side"], explain: "The final step in PASS is to Sweep the extinguisher from side to side at the base of the fire.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'fib', q: "For Class A hazards, the maximum travel distance to a fire extinguisher is ___ feet.", answer: "75", accept: ["seventy-five"], explain: "OSHA requires Class A extinguishers to be within 75 feet of travel.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'fib', q: "For Class B and C hazards, the maximum travel distance to a fire extinguisher is ___ feet.", answer: "50", accept: ["fifty"], explain: "Class B and C extinguishers must be within 50 feet of travel.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'fib', q: "A flammable liquid has a flash point below ___ °F.", answer: "100", accept: ["one hundred"], explain: "Liquids with flash points below 100°F are classified as flammable.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'fib', q: "Portable fire extinguishers must be visually inspected at least ___ per year.", answer: "monthly", accept: ["12 times", "once a month"], explain: "OSHA requires monthly (at minimum) visual inspections of portable fire extinguishers.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'fib', q: "Smoking must not occur within ___ feet of flammable materials.", answer: "20", accept: ["twenty"], explain: "A minimum 20-foot no-smoking buffer is required around flammable materials.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'fib', q: "Temporary heaters on construction sites must maintain at least ___ feet of clearance from combustibles.", answer: "3", accept: ["three"], explain: "A 3-foot clearance from combustible materials is required for temporary heating devices.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'fib', q: "A fire watch must be maintained for a minimum of ___ minutes after hot work is completed.", answer: "30", accept: ["thirty"], explain: "OSHA and NFPA require a minimum 30-minute fire watch after hot work ends to catch smoldering fires.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },

    // ── SA (44-50)
    { type: 'sa', q: "Which of the following are examples of Class B flammable/combustible hazards? (Select all that apply)", options: ["Gasoline", "Wood shavings", "Propane gas", "Diesel fuel"], answers: [0, 2, 3], explain: "Gasoline, propane, and diesel fuel are all Class B flammable/combustible liquid or gas hazards. Wood shavings are Class A.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'sa', q: "Which of the following are required elements of a fire watch? (Select all that apply)", options: ["A trained designated fire watch person", "Fire extinguisher readily available", "Fire watch maintained at least 30 minutes after work", "Hot work permit displayed nearby"], answers: [0, 1, 2], explain: "A fire watch requires a trained person, accessible extinguisher, and a minimum 30-minute post-work watch period.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'sa', q: "Which statements about CO2 fire extinguishers are correct? (Select all that apply)", options: ["They are effective on energized electrical fires", "They leave no conductive residue", "They are the best choice for Class A fires in open areas", "They work by displacing oxygen"], answers: [0, 1, 3], explain: "CO2 works on electrical fires, leaves no residue, and displaces oxygen. It is not preferred for Class A fires in open areas because the CO2 dissipates quickly.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'sa', q: "Which of the following are proper storage requirements for flammable liquids on construction sites? (Select all that apply)", options: ["More than 10 gallons must be in a listed container", "More than 25 gallons must be in an approved storage room", "Flammable liquids may be stored near ignition sources if labeled", "Containers must be kept closed when not in use"], answers: [0, 1, 3], explain: "Proper storage requires listed containers above 10 gallons, a storage room above 25 gallons, and keeping containers closed. Storage near ignition sources is never permitted.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'sa', q: "Which of the following are correct steps in the PASS technique? (Select all that apply)", options: ["Pull the safety pin", "Aim at the base of the fire", "Spray at the top of the flames first", "Sweep side to side"], answers: [0, 1, 3], explain: "PASS: Pull, Aim at the base, Squeeze, Sweep. Spraying at the top of flames is incorrect.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'sa', q: "Which of the following fire prevention practices are required on construction sites? (Select all that apply)", options: ["No smoking within 20 feet of flammable materials", "Monthly inspection of fire extinguishers", "Storing combustible waste in covered metal containers", "Leaving extinguishers in the job trailer for safekeeping"], answers: [0, 1, 2], explain: "Smoking buffers, monthly extinguisher inspections, and proper waste storage are all required. Extinguishers must be accessible on-site, not locked in a trailer.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
    { type: 'sa', q: "Which of the following are true about hot work permits? (Select all that apply)", options: ["They are required for welding and cutting in fire-hazard areas", "They must document the location and type of hot work", "They eliminate the need for a fire watch", "They must specify the time period of authorized hot work"], answers: [0, 1, 3], explain: "Hot work permits are required in fire-hazard areas and must include location, work type, and authorized time period. A fire watch is still required; the permit does not eliminate it.", moduleRef: 17, moduleName: "Fire Protection & Prevention" },
  ],

  18: [
    // ── Module 18 · Welding & Cutting ── MC (1-35)
    { type: 'mc', q: "What is the maximum working pressure for acetylene gas?", options: ["5 psi", "10 psi", "15 psi", "30 psi"], a: 2, explain: "Acetylene must never be used at pressures above 15 psi; above this pressure it becomes shock-sensitive and can decompose explosively.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "The maximum withdrawal rate from an acetylene cylinder is:", options: ["1/5 of the cylinder capacity per hour", "1/7 of the cylinder capacity per hour", "1/10 of the cylinder capacity per hour", "1/3 of the cylinder capacity per hour"], a: 1, explain: "Withdrawing more than 1/7 of cylinder capacity per hour may cause acetone (the stabilizer) to be withdrawn with the gas, creating a hazard.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "When oxygen and fuel gas cylinders are stored together, they must be separated by at least:", options: ["10 feet OR a 5-foot fire-resistant barrier", "20 feet OR a 5-foot fire-resistant barrier", "30 feet OR a 10-foot fire-resistant barrier", "5 feet at all times"], a: 1, explain: "Oxygen and fuel gas cylinders must be separated by 20 feet OR a minimum 5-foot-high fire-resistant barrier.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Gas cylinders not in use must be stored:", options: ["On their side to prevent valve damage", "Upright with valve cap secured", "In a horizontal rack", "Upside down to prevent moisture entry"], a: 1, explain: "Cylinders must be stored upright and secured, with protective valve caps in place when not in use.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Arc welding UV and infrared radiation can cause a painful eye condition called:", options: ["Cataracts", "Glaucoma", "Photokeratitis (arc eye)", "Night blindness"], a: 2, explain: "UV radiation from arc welding causes photokeratitis, commonly called 'arc eye' or 'welder's flash,' which is a painful inflammation of the cornea.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "What lens shade is appropriate for arc welding?", options: ["Shade 2–4", "Shade 5–6", "Shade 8–9", "Shade 10–14"], a: 3, explain: "Arc welding requires lens shades 10 through 14 depending on amperage; gas welding typically uses shade 5.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "What lens shade is appropriate for gas (oxy-fuel) welding?", options: ["Shade 3", "Shade 5", "Shade 8", "Shade 10"], a: 1, explain: "Gas welding typically requires shade 5 lenses, which is much lower than arc welding requirements.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "The minimum ventilation required for arc welding in an open area is:", options: ["500 cubic feet per welder", "1,000 cubic feet per welder", "2,000 cubic feet per welder", "4,000 cubic feet per welder"], a: 2, explain: "OSHA requires a minimum of 2,000 cubic feet of space per welder with adequate air movement for general welding ventilation.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "In a confined space, how must ventilation be provided during welding?", options: ["Open the nearest window", "Use oxygen from a spare welding cylinder", "Continuous forced-air ventilation", "Permit natural air circulation only"], a: 2, explain: "Confined space welding requires continuous forced-air (mechanical) ventilation to remove fumes and maintain oxygen levels.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Why must oxygen NEVER be used to ventilate a confined space during welding?", options: ["It reacts with the metal being welded", "It creates an oxygen-enriched atmosphere that dramatically increases fire and explosion risk", "It is too expensive", "It corrodes the welding equipment"], a: 1, explain: "Using pure oxygen for ventilation creates an oxygen-enriched atmosphere in which materials that normally would not burn easily ignite and burn violently.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "The permissible exposure limit (PEL) for hexavalent chromium (Cr(VI)) is:", options: ["1 µg/m³", "5 µg/m³", "50 µg/m³", "100 µg/m³"], a: 1, explain: "OSHA's PEL for hexavalent chromium is 5 micrograms per cubic meter of air as an 8-hour TWA.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Hexavalent chromium (Cr(VI)) exposure is a hazard primarily when welding:", options: ["Mild carbon steel", "Stainless steel", "Aluminum alloys", "Cast iron"], a: 1, explain: "Welding stainless steel generates Cr(VI) fumes from the chromium content, which is a known human carcinogen.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Welding galvanized steel produces fumes of:", options: ["Lead oxide", "Manganese", "Zinc oxide", "Hexavalent chromium"], a: 2, explain: "Galvanized steel is coated with zinc; heating it produces zinc oxide fumes that cause metal fume fever.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Metal fume fever is primarily caused by inhaling:", options: ["Hexavalent chromium fumes", "Carbon monoxide", "Zinc oxide fumes from galvanized steel", "Ozone from arc welding"], a: 2, explain: "Metal fume fever is an acute flu-like condition caused by inhaling freshly formed zinc oxide fumes, most commonly during galvanized steel welding.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Flashback arrestors in oxy-fuel welding systems must be installed:", options: ["On the torch only", "On the regulators only", "On both the torch and the regulators", "Only on oxygen systems"], a: 2, explain: "Flashback arrestors must be installed on both the torch and the regulators to prevent flame propagation back into the hoses and cylinders.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "The purpose of welding screens is to:", options: ["Block wind from affecting the weld", "Protect other workers from UV/infrared radiation and arc flash", "Prevent sparks from reaching combustibles", "Contain welding fumes"], a: 1, explain: "Welding screens protect nearby workers from the harmful UV and infrared radiation produced by the welding arc.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Hot electrode stubs must be disposed of in:", options: ["A bucket of water", "A metal container designated for stubs", "The nearest waste bin", "On the ground away from combustibles"], a: 1, explain: "Hot electrode stubs must go into a designated metal container to prevent fire from contact with combustible materials.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "The OSHA standard governing welding and cutting in construction is:", options: ["29 CFR 1926 Subpart F", "29 CFR 1926 Subpart J", "29 CFR 1926 Subpart Q", "29 CFR 1910.252"], a: 1, explain: "Welding and cutting in construction is governed by 29 CFR 1926 Subpart J.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Before welding on a container that previously held flammable materials, the container must be:", options: ["Painted over to seal residue", "Filled with water first", "Properly cleaned and inerted or purged", "Labeled 'hazardous contents'"], a: 2, explain: "Containers that held flammables must be thoroughly cleaned and inerted (purged of flammable vapors) before any hot work is performed.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "A hot work permit is required when welding or cutting in an area where:", options: ["Any other workers are present", "Sprinkler systems are active", "There is a fire hazard from combustibles or flammables", "The temperature exceeds 90°F"], a: 2, explain: "Hot work permits are required whenever welding or cutting is done in areas with fire hazards from combustible or flammable materials.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Which of the following is a primary control measure for Cr(VI) exposure during stainless steel welding?", options: ["Weld faster to reduce exposure time", "Use local exhaust ventilation (LEV)", "Use shade 5 welding lenses", "Apply barrier cream to exposed skin"], a: 1, explain: "Local exhaust ventilation is the primary engineering control for reducing Cr(VI) exposure at the source.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Oxygen cylinders must be kept away from oil, grease, or petroleum products because:", options: ["Oil contaminates the weld", "Oxygen reacts violently with oil, potentially causing ignition or explosion", "It damages the cylinder threads", "OSHA prohibits mixing these materials"], a: 1, explain: "Oxygen reacting with hydrocarbons (oil, grease) can cause spontaneous ignition or explosion even without a separate ignition source.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "What type of respirator is minimally required when welding stainless steel without adequate ventilation?", options: ["A dust mask (nuisance mask)", "A half-face air-purifying respirator with appropriate cartridges", "No respirator is required", "A supplied-air respirator only"], a: 1, explain: "When engineering controls are insufficient, a half-face air-purifying respirator with appropriate particulate/P100 cartridges is the minimum required for Cr(VI) protection.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "When welding outdoors, the area around the work must be cleared of combustibles within:", options: ["5 feet", "10 feet", "35 feet", "50 feet"], a: 2, explain: "OSHA/NFPA standards require combustibles to be cleared or protected within 35 feet of hot work operations.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Which of the following describes a flashback in an oxy-fuel system?", options: ["The torch flame going out unexpectedly", "Flame traveling backward into the hoses or cylinder", "Excess oxygen pressure at the torch", "An electric arc jumping to the regulator"], a: 1, explain: "Flashback occurs when the flame burns back through the hose toward the regulator or cylinder, creating an explosion hazard.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Gas hoses on oxy-fuel equipment are color-coded: oxygen is ___ and fuel gas (acetylene) is ___.", options: ["Blue / Red", "Green / Red", "Red / Blue", "Yellow / Green"], a: 1, explain: "OSHA/CGA standards color-code oxygen hoses green and fuel gas (acetylene) hoses red.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Arc flash and UV radiation from welding require nearby workers to be protected by:", options: ["Hard hats with face shields", "Welding screens or equivalent barriers", "Safety glasses alone", "No protection needed beyond 10 feet"], a: 1, explain: "Welding screens or barriers must be used to protect other workers from arc flash and UV radiation.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "When should cylinders be moved using a cart or hand truck?", options: ["Only when fully empty", "Whenever they are transported any significant distance", "Only if they weigh more than 50 pounds", "Never — cylinders must stay in place"], a: 1, explain: "Cylinders should always be transported using an appropriate hand truck or cylinder cart to prevent tipping and valve damage.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Welding in a confined space requires which additional precaution beyond normal welding requirements?", options: ["OSHA written concurrence", "Confined space entry permit and continuous air monitoring", "Hot work permit is waived for confined spaces", "Welding screens inside the space"], a: 1, explain: "Confined space welding requires a confined space entry permit, continuous forced air ventilation, and continuous atmospheric monitoring.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "The primary purpose of a regulator on a gas cylinder is to:", options: ["Measure remaining gas volume", "Reduce high cylinder pressure to safe working pressure", "Prevent gas from escaping when the torch is off", "Indicate the type of gas in the cylinder"], a: 1, explain: "Regulators reduce the high storage pressure of the cylinder to a safe, controllable working pressure for the torch.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Under OSHA Subpart J, when must fire watch be maintained after welding or cutting?", options: ["Only during the welding operation", "For 30 minutes minimum after work stops", "Until the end of the work shift", "Only in confined spaces"], a: 1, explain: "A fire watch must be maintained for at least 30 minutes after welding or cutting ceases to detect any smoldering fires.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "What is the primary hazard of using acetylene above 15 psi?", options: ["It burns too cool for welding", "It becomes shock-sensitive and can explosively decompose", "It reacts with oxygen in the regulator", "It corrodes copper fittings"], a: 1, explain: "Above 15 psi, acetylene can undergo shock-sensitive decomposition that can cause an explosion even without a separate ignition source.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Electrode holders used for arc welding must be:", options: ["Fully insulated to protect against electric shock", "Bare metal for better conductivity", "Grounded to the workpiece", "Rated for the maximum output of any available power source"], a: 0, explain: "Electrode holders must be fully insulated to protect the welder from electric shock.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Which of the following welding operations generates the greatest UV radiation exposure to nearby workers?", options: ["Gas (oxy-acetylene) welding", "Soldering", "Shielded metal arc welding (SMAW)", "Braze welding"], a: 2, explain: "Arc welding processes like SMAW generate intense UV radiation that can cause arc eye and skin burns even at distances from the work.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'mc', q: "Welding fume exposure in confined areas is best controlled by:", options: ["Opening nearby doors and windows only", "Local exhaust ventilation (LEV) positioned at the source", "Relying on general dilution ventilation", "Requiring workers to hold their breath during welds"], a: 1, explain: "Local exhaust ventilation captures fumes at the source before they disperse, providing the most effective control.", moduleRef: 18, moduleName: "Welding & Cutting" },

    // ── FIB (36-43)
    { type: 'fib', q: "Acetylene must never be used at pressures above ___ psi.", answer: "15", accept: ["fifteen"], explain: "Above 15 psi, acetylene becomes shock-sensitive and can explosively decompose.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'fib', q: "Oxygen and fuel gas cylinders stored together must be separated by ___ feet or a fire-resistant barrier.", answer: "20", accept: ["twenty"], explain: "A 20-foot separation or a 5-foot-high fire-resistant barrier is required between oxygen and fuel gas cylinders.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'fib', q: "The recommended minimum space per welder for general ventilation in arc welding is ___ cubic feet.", answer: "2000", accept: ["2,000", "two thousand"], explain: "OSHA requires 2,000 cubic feet of air space per welder as the minimum for adequate general ventilation.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'fib', q: "The OSHA permissible exposure limit for hexavalent chromium (Cr(VI)) is ___ µg/m³ as an 8-hour TWA.", answer: "5", accept: ["five"], explain: "The OSHA PEL for Cr(VI) is 5 micrograms per cubic meter as an 8-hour time-weighted average.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'fib', q: "For arc welding, the appropriate lens shade range is shade ___ to ___.", answer: "10 to 14", accept: ["10-14", "shade 10 to 14"], explain: "Arc welding requires protective lens shades between 10 and 14 depending on the amperage used.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'fib', q: "Welding on galvanized steel produces ___ oxide fumes that cause metal fume fever.", answer: "zinc", accept: ["zinc oxide"], explain: "Galvanized coatings are zinc; when heated they produce zinc oxide fumes causing metal fume fever.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'fib', q: "Flashback arrestors must be installed on both the ___ and the regulators of oxy-fuel systems.", answer: "torch", accept: ["torches"], explain: "Both the torch and regulators require flashback arrestors to prevent flame from traveling back through the hoses.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'fib', q: "A fire watch must be maintained for a minimum of ___ minutes after welding or cutting operations cease.", answer: "30", accept: ["thirty"], explain: "A 30-minute minimum fire watch is required after any welding or cutting operation to detect smoldering fires.", moduleRef: 18, moduleName: "Welding & Cutting" },

    // ── SA (44-50)
    { type: 'sa', q: "Which of the following are required precautions for welding in a confined space? (Select all that apply)", options: ["Continuous forced-air ventilation", "Confined space entry permit", "Use oxygen from a spare cylinder to ventilate", "Continuous atmospheric monitoring"], answers: [0, 1, 3], explain: "Confined space welding requires forced-air ventilation, an entry permit, and continuous air monitoring. Oxygen must NEVER be used for ventilation.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'sa', q: "Which of the following are correct requirements for gas cylinder storage? (Select all that apply)", options: ["Stored upright and secured", "Valve caps in place when not in use", "Stored on their sides for stability", "Oxygen and fuel gas separated by 20 feet or a barrier"], answers: [0, 1, 3], explain: "Cylinders must be stored upright, secured, with caps on, and oxygen/fuel gas must be separated. Storing on their sides is incorrect.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'sa', q: "Which of the following are hazards specifically associated with welding stainless steel? (Select all that apply)", options: ["Hexavalent chromium (Cr(VI)) fumes", "Zinc oxide fumes", "UV radiation causing arc eye", "Carcinogenic fume exposure"], answers: [0, 2, 3], explain: "Stainless steel welding produces Cr(VI) fumes (carcinogenic) and UV radiation causing arc eye. Zinc oxide fumes come from galvanized steel.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'sa', q: "Which of the following are correct practices for oxy-fuel cylinder use? (Select all that apply)", options: ["Never use acetylene above 15 psi", "Install flashback arrestors on torch and regulators", "Oxygen hoses are color-coded green", "Cylinders may be stored on their sides when in use"], answers: [0, 1, 2], explain: "Acetylene pressure limits, flashback arrestors, and green oxygen hose color coding are all correct. Cylinders must always remain upright.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'sa', q: "Which of the following are effective controls for welding fume hazards? (Select all that apply)", options: ["Local exhaust ventilation at the source", "General dilution ventilation at 2,000 cu ft per welder", "Welding faster to reduce exposure time", "Appropriate respiratory protection when ventilation is insufficient"], answers: [0, 1, 3], explain: "LEV, general dilution ventilation, and respirators are accepted controls. Welding faster is not a recognized engineering control.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'sa', q: "Which of the following are requirements for hot work permits during welding operations? (Select all that apply)", options: ["Required when welding in fire-hazard areas", "Must specify the authorized time period", "Replace the need for a fire watch", "Must identify combustibles in the area"], answers: [0, 1, 3], explain: "Hot work permits are required in fire-hazard areas, must document the time period and identify combustibles, but do NOT replace the fire watch requirement.", moduleRef: 18, moduleName: "Welding & Cutting" },
    { type: 'sa', q: "Which of the following are true about electrode stub disposal during arc welding? (Select all that apply)", options: ["Hot stubs must go in a designated metal container", "Stubs can be dropped on the ground if away from combustibles", "Electrode stubs pose a fire hazard", "Proper disposal prevents fires from smoldering stubs"], answers: [0, 2, 3], explain: "Hot stubs must be placed in metal containers because they are a fire hazard. Dropping them on the ground — even away from combustibles — is not an acceptable practice.", moduleRef: 18, moduleName: "Welding & Cutting" },
  ],

  19: [
    // ── Module 19 · Motor Vehicles & Equipment ── MC (1-35)
    { type: 'mc', q: "When must a pre-operational inspection be performed on construction equipment?", options: ["Once a week", "Before each shift", "Monthly", "Only when a defect is suspected"], a: 1, explain: "OSHA requires a pre-operational inspection of equipment before each shift to identify and correct defects before operation.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "What does ROPS stand for?", options: ["Roll-Over Protection System", "Rollover Protective Structure", "Rear Operating Protection Shield", "Rigid Overhead Protective System"], a: 1, explain: "ROPS stands for Rollover Protective Structure, which protects the operator in the event of a vehicle rollover.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "ROPS is required on which of the following types of equipment?", options: ["Forklifts only", "Earthmoving equipment including dozers, graders, compactors, scrapers, and loaders", "Aerial lifts only", "Cranes and hoists"], a: 1, explain: "ROPS is required on most earthmoving equipment including dozers, motor graders, compactors, scrapers, and loaders.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "What does FOPS stand for and what does it protect against?", options: ["Fall Object Protection System — side collisions", "Falling Object Protective Structure — falling objects striking the operator", "Forward Operating Protective Shield — debris from the front", "Fixed Object Protection System — collisions with fixed structures"], a: 1, explain: "FOPS (Falling Object Protective Structure) protects the equipment operator from falling objects such as rocks or debris.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "When ROPS is installed on equipment, the operator must:", options: ["Remove it when working in tight spaces", "Always wear the seat belt", "Adjust it to the highest position", "Inspect it weekly only"], a: 1, explain: "When ROPS is present, the seat belt must always be worn so the operator stays within the protective envelope during a rollover.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Passengers may ride on equipment only when:", options: ["The speed is below 10 mph", "An additional seat and seat belt are provided", "The operator gives permission", "The site superintendent approves verbally"], a: 1, explain: "No riders are allowed unless the equipment has an additional designed seat with a seat belt for each passenger.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Backup alarms are required when:", options: ["The equipment is over 10,000 lbs", "The operator's rearward view is obstructed", "Working at night only", "The site has more than 10 workers"], a: 1, explain: "Backup alarms are required whenever an operator's view to the rear is obstructed; alternatively, a spotter may be used.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "When a spotter is used instead of a backup alarm, the spotter must:", options: ["Stand directly behind the vehicle", "Remain in constant view of the operator", "Hold a flag at all times", "Have a radio at all times"], a: 1, explain: "The spotter must remain in a position where the operator can always see them to effectively guide the backing maneuver.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "The maximum speed for equipment in pedestrian areas on a construction site is:", options: ["5 mph", "3 mph", "10 mph", "15 mph"], a: 1, explain: "OSHA limits equipment speed in pedestrian traffic areas to 3 mph to prevent pedestrian strikes.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Flaggers directing traffic on construction sites must wear at minimum a:", options: ["Class 1 high-visibility vest", "Class 2 high-visibility vest", "Class 3 high-visibility vest", "Any brightly colored shirt"], a: 1, explain: "OSHA requires flaggers to wear at least a Class 2 high-visibility safety vest.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Traffic flaggers must use which approved devices to control traffic?", options: ["Hand signals only", "Stop/slow paddle or flag", "Whistle and hand signals only", "Orange cones only"], a: 1, explain: "Flaggers must use a STOP/SLOW paddle or an approved flag to control traffic — hand signals alone are not sufficient.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "The OSHA construction standard for motor vehicles and equipment is found in:", options: ["29 CFR 1926 Subpart N", "29 CFR 1926 Subpart O", "29 CFR 1926 Subpart P", "29 CFR 1910.178"], a: 1, explain: "Motor vehicles and equipment on construction sites are governed by 29 CFR 1926 Subpart O.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "What protection is addressed by 29 CFR 1926 Subpart W?", options: ["Working over water", "Rollover protection structures (ROPS) and overhead protection", "Working with explosives", "Welding and cutting"], a: 1, explain: "29 CFR 1926 Subpart W specifically addresses rollover protective structures (ROPS) and overhead protection for construction equipment.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "When must you call 811 (Call Before You Dig)?", options: ["Only when excavating near highways", "Before any excavation near underground utilities", "Only for excavations deeper than 5 feet", "Only on public property"], a: 1, explain: "811 must be called before any excavation activity to have underground utilities marked, regardless of depth or ownership.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "The minimum width of haul roads on construction sites should be:", options: ["Equal to the width of the widest vehicle", "1.5 times the width of the widest vehicle", "2 times the width of the widest vehicle", "3 times the width of the widest vehicle"], a: 2, explain: "Haul roads should be at least twice the width of the widest vehicle to allow safe passing and operation.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Aerial lifts are governed by which standard?", options: ["ANSI A10.28", "ANSI A92", "29 CFR 1910.269", "ANSI B56.6"], a: 1, explain: "Aerial lifts (boom lifts, scissor lifts, etc.) must comply with ANSI A92 standards.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Workers in aerial lifts must NOT:", options: ["Wear a harness anchored to the lift basket", "Tie off to an adjacent structure while the boom is elevated", "Use the lift's fall protection anchor point", "Ensure the platform is within the rated load"], a: 1, explain: "Workers must never tie off to an adjacent structure while in a boom lift; they must anchor only to designated anchor points on the lift itself.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Scissor lifts must NOT be used to:", options: ["Elevate workers vertically", "Travel while in the elevated position on uneven or sloped terrain", "Support materials within rated capacity", "Provide a work platform within design limits"], a: 1, explain: "Scissor lifts must not be driven in the elevated position on uneven terrain, which creates a tipping hazard.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "What must be done before an aerial lift is used?", options: ["Written OSHA approval obtained", "Pre-use inspection and operator training verification", "Only a visual check by the supervisor", "Annual certification from the manufacturer"], a: 1, explain: "A pre-use inspection and verification that the operator is trained and authorized are required before each aerial lift use.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Which of the following is an example of earthmoving equipment that typically requires ROPS?", options: ["Tower crane", "Concrete pump", "Motor grader", "Pneumatic nailer"], a: 2, explain: "Motor graders are earthmoving equipment for which ROPS is required by OSHA.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "If a pre-operational equipment inspection reveals a defect, the operator should:", options: ["Continue operating at reduced speed", "Report it and remove the equipment from service until repaired", "Fix it during the lunch break", "Log it at the end of the shift"], a: 1, explain: "Any defect found during pre-operational inspection must be reported and the equipment taken out of service until repaired.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "What is the purpose of requiring backup alarms or spotters on construction equipment?", options: ["To signal the end of the work shift", "To prevent struck-by accidents when equipment moves in reverse", "To satisfy insurance requirements", "To alert workers to start their engines"], a: 1, explain: "Backup alarms and spotters are required to prevent workers from being struck by equipment backing up when the operator cannot see behind the machine.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "When should equipment engines be shut off before performing maintenance?", options: ["Only when changing fluids", "Always, before any maintenance or repair unless the task requires the engine running", "Never, the engine should idle during service", "Only if the battery is low"], a: 1, explain: "Engines must be shut down before performing maintenance or repairs to prevent injury from moving parts, unless the specific task requires the engine to run.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Which of the following is the correct definition of a 'spotter' in construction equipment operations?", options: ["A worker who paints ground markings", "A trained worker who guides equipment operators in areas with blind spots or pedestrians", "A surveyor marking property boundaries", "An OSHA compliance inspector"], a: 1, explain: "A spotter is a trained worker who guides equipment operators around blind spots, near pedestrians, or in congested areas.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "ROPS must not be modified or removed because:", options: ["It voids the equipment warranty only", "Alterations can compromise its structural integrity and effectiveness in a rollover", "OSHA will issue an immediate fine", "The manufacturer prohibits it for liability reasons only"], a: 1, explain: "ROPS must not be altered because any modification can reduce its effectiveness in a rollover and may cause it to fail.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Which organization establishes standards for the design and testing of aerial work platforms?", options: ["OSHA", "ANSI", "NIOSH", "NFPA"], a: 1, explain: "ANSI (specifically ANSI A92) establishes design and performance standards for aerial work platforms.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Operators of aerial lifts must be:", options: ["Licensed by OSHA", "Trained and authorized per ANSI A92 and OSHA requirements", "Certified by a third-party testing agency annually", "Supervised by the general contractor at all times"], a: 1, explain: "OSHA and ANSI A92 require that aerial lift operators be trained and authorized before operating the equipment.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "What must be checked to ensure a scissor lift is not overloaded?", options: ["The color of the hydraulic fluid", "The platform weight against the rated load capacity", "The tire pressure", "The hours of operation since last service"], a: 1, explain: "The combined weight of workers, tools, and materials on the platform must never exceed the manufacturer's rated load capacity.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Which type of sign/signal is used by a flagger to stop traffic?", options: ["A green flag waved overhead", "The STOP face of the stop/slow paddle", "A whistle blast", "A flashing amber light"], a: 1, explain: "Flaggers use the 'STOP' face of the stop/slow paddle to stop traffic and the 'SLOW' face to allow traffic to proceed slowly.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "At what minimum visibility level are flaggers generally required to wear retroreflective high-visibility vests?", options: ["Only at night", "In all lighting conditions (daytime and nighttime) on active construction sites", "Only during precipitation", "Only in school zones"], a: 1, explain: "High-visibility vests (Class 2 minimum) are required during all conditions — day and night — when flaggers are working on active construction sites.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Which phone number must be called before excavating near underground utilities?", options: ["911", "311", "811", "411"], a: 2, explain: "811 is the national 'Call Before You Dig' number that connects callers to local utility notification centers.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Earthmoving equipment should be refueled:", options: ["While the engine is running to save time", "Only with the engine off and no open flames nearby", "At any time the tank reads below half", "Using any available fuel container"], a: 1, explain: "Equipment must be refueled with the engine off and away from ignition sources including open flames to prevent fire.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "Which of the following is the PRIMARY hazard addressed by ROPS?", options: ["Falling objects from overhead", "Equipment tipping and rollover injuring the operator", "Runaway equipment", "Electrical contact from overhead lines"], a: 1, explain: "ROPS is designed to prevent operator crush injuries when earthmoving equipment tips over or rolls over.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "An equipment operator notices their backup alarm is not functioning. What is the correct response?", options: ["Continue working with extra caution", "Use a spotter or immediately repair the alarm before resuming reverse operations", "Honk the horn instead", "Work until the end of the shift then report it"], a: 1, explain: "If the backup alarm is non-functional, a spotter must be used or the alarm repaired before the equipment can back up safely.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'mc', q: "When traveling haul roads on a construction site, the minimum road width must be at least:", options: ["Equal to the vehicle width plus 2 feet", "1.5 times the widest vehicle width", "2 times the widest vehicle width", "3 times the widest vehicle width"], a: 2, explain: "OSHA requires haul roads to be at least twice the width of the widest vehicle using the road.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },

    // ── FIB (36-43)
    { type: 'fib', q: "ROPS stands for Rollover ___ Structure.", answer: "Protective", accept: ["protective"], explain: "ROPS = Rollover Protective Structure, designed to protect the operator during an equipment rollover.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'fib', q: "FOPS stands for Falling Object ___ Structure.", answer: "Protective", accept: ["protective"], explain: "FOPS = Falling Object Protective Structure, which shields the operator from overhead falling hazards.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'fib', q: "Equipment in pedestrian areas on construction sites must not exceed ___ mph.", answer: "3", accept: ["three"], explain: "OSHA limits equipment speed to 3 mph in areas where pedestrian workers are present.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'fib', q: "Construction site haul roads must be at least ___ times the width of the widest vehicle.", answer: "2", accept: ["two", "twice"], explain: "Haul roads must be at least 2 times (double) the width of the widest vehicle using them.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'fib', q: "The national phone number to call before excavating near underground utilities is ___.", answer: "811", accept: ["8-1-1"], explain: "811 is the federally designated 'Call Before You Dig' number.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'fib', q: "Flaggers directing construction traffic must wear at minimum a Class ___ high-visibility safety vest.", answer: "2", accept: ["two"], explain: "OSHA requires flaggers to wear at least a Class 2 high-visibility vest.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'fib', q: "When ROPS is installed on equipment, the operator must wear a ___ at all times.", answer: "seat belt", accept: ["seatbelt", "safety belt"], explain: "The seat belt must be worn whenever ROPS is present to keep the operator within the protective envelope.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'fib', q: "Aerial lifts used on construction sites must comply with ANSI ___ standards.", answer: "A92", accept: ["ANSI A92"], explain: "ANSI A92 is the national consensus standard series governing aerial work platforms.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },

    // ── SA (44-50)
    { type: 'sa', q: "Which of the following are required when passengers ride on construction equipment? (Select all that apply)", options: ["An additional designed seat for each passenger", "A seat belt for each passenger", "Operator verbal consent only", "Speed not to exceed 5 mph"], answers: [0, 1], explain: "Passengers are only allowed when there is an additional designed seat and seat belt for each passenger. Verbal consent and speed limits alone are not the regulatory requirements.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'sa', q: "Which of the following types of earthmoving equipment typically require ROPS? (Select all that apply)", options: ["Bulldozer (dozer)", "Motor grader", "Tower crane", "Soil compactor"], answers: [0, 1, 3], explain: "Dozers, motor graders, and compactors are earthmoving equipment requiring ROPS. Tower cranes are not earthmoving equipment and have different protections.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'sa', q: "Which of the following are correct requirements for equipment backup safety? (Select all that apply)", options: ["Backup alarm required when operator's rear view is obstructed", "A spotter may be used in lieu of a backup alarm", "Spotter must remain in constant view of the operator", "Backup alarms are optional if the site is small"], answers: [0, 1, 2], explain: "Backup alarms or spotters are required when rear view is obstructed. Spotters must remain visible to the operator. Small site size does not eliminate the requirement.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'sa', q: "Which of the following are correct practices for aerial lift operations? (Select all that apply)", options: ["Workers must be trained and authorized before operating", "Workers may tie off to adjacent structures when working at height", "Personal fall arrest system must be used per manufacturer requirements", "Platform load must not exceed rated capacity"], answers: [0, 2, 3], explain: "Operators must be trained, wear PFAS as required, and not exceed rated load. Tying off to adjacent structures while in a boom lift is prohibited.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'sa', q: "Which of the following are required elements of a pre-operational equipment inspection? (Select all that apply)", options: ["Check fluid levels and leaks", "Test brakes and steering", "Verify backup alarm is functional", "Complete the inspection once per week only"], answers: [0, 1, 2], explain: "Pre-operational inspections must include fluids, brakes, steering, backup alarms, and other safety systems. Inspections are required before each shift, not weekly.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'sa', q: "Which of the following are required safety measures before excavating near underground utilities? (Select all that apply)", options: ["Call 811 to have utilities marked", "Wait for utility owners to mark lines before digging", "Visually inspect the area for surface utility indicators", "Excavate immediately if no markings are visible within 24 hours"], answers: [0, 1, 2], explain: "Calling 811, waiting for markings, and visual inspection are all required steps. Excavating before utilities are marked is prohibited.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
    { type: 'sa', q: "Which of the following actions are prohibited when operating a scissor lift? (Select all that apply)", options: ["Exceeding the rated load capacity", "Traveling while elevated on uneven terrain", "Wearing a harness inside the platform", "Parking on a slope without wheel chocks"], answers: [0, 1, 3], explain: "Exceeding rated load, traveling elevated on uneven terrain, and parking on slopes without chocks are prohibited. Wearing a harness inside the platform is generally a safe and recommended practice.", moduleRef: 19, moduleName: "Motor Vehicles & Equipment" },
  ],

  20: [
    // ── Module 20 · Confined Spaces ── MC (1-35)
    { type: 'mc', q: "Which OSHA standard governs confined spaces in construction?", options: ["29 CFR 1910.146", "29 CFR 1926.1200–1213", "29 CFR 1926 Subpart P", "29 CFR 1910.119"], a: 1, explain: "Confined spaces in construction are governed by 29 CFR 1926.1200 through 1213, which became effective in 2015.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "What are the three defining characteristics of a confined space?", options: ["Permit required, one entry/exit, hazardous atmosphere", "Large enough to enter, limited entry/exit, not designed for continuous occupancy", "Underground, small opening, requires permit", "Enclosed, ventilated, below grade"], a: 1, explain: "A confined space is: (1) large enough for a worker to enter, (2) has limited means of entry or exit, and (3) is not designed for continuous occupancy.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "A permit-required confined space (PRCS) is defined as a confined space that also has:", options: ["At least one recognized serious hazard such as a hazardous atmosphere or engulfment potential", "No ventilation system", "A depth greater than 4 feet", "Asbestos-containing materials"], a: 0, explain: "A PRCS is a confined space that contains or has the potential to contain at least one serious hazard: hazardous atmosphere, engulfment material, internal geometry that traps occupants, or any other recognized serious safety or health hazard.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Which of the following is NOT a condition that makes a confined space permit-required?", options: ["Hazardous atmosphere", "Engulfment material present", "Limited entry and exit", "Internal shape that could trap a worker"], a: 2, explain: "Limited entry/exit is part of the definition of any confined space, not a condition that makes it permit-required. A PRCS requires a recognized serious hazard.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "What is the correct order for atmospheric testing in a confined space?", options: ["Toxic, flammable, oxygen", "Oxygen, flammable, toxic", "Flammable, oxygen, toxic", "Toxic, oxygen, flammable"], a: 1, explain: "Atmospheric testing must be performed in order: 1) Oxygen content, 2) Flammable gases (LEL), 3) Toxic contaminants.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Oxygen deficiency in a confined space is defined as an oxygen concentration below:", options: ["18%", "19.5%", "21%", "23.5%"], a: 1, explain: "An oxygen concentration below 19.5% constitutes oxygen deficiency and is immediately dangerous without supplied-air respiratory protection.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Oxygen enrichment in a confined space is defined as an oxygen concentration above:", options: ["21%", "22%", "23.5%", "25%"], a: 2, explain: "Oxygen concentration above 23.5% constitutes oxygen enrichment, dramatically increasing fire and explosion risk.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "What does LEL stand for?", options: ["Lower Entry Limit", "Lower Explosive Limit", "Level of Exposure Limit", "Lethal Exposure Limit"], a: 1, explain: "LEL stands for Lower Explosive Limit — the minimum concentration of a flammable gas in air that can be ignited.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "A confined space atmosphere is considered safe for entry when flammable gas concentrations are below:", options: ["25% of the LEL", "10% of the LEL", "50% of the LEL", "5% of the LEL"], a: 1, explain: "OSHA requires that flammable gas concentrations be below 10% of the LEL before workers may enter a confined space.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "What does IDLH stand for?", options: ["Immediately Deficient Level for Humans", "Immediately Dangerous to Life or Health", "Internal Danger Level for Hazards", "Inhalation Damage Level for Health"], a: 1, explain: "IDLH — Immediately Dangerous to Life or Health — represents the concentration at which a worker could be seriously harmed or unable to escape in 30 minutes.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Who is responsible for authorizing entry into a permit-required confined space?", options: ["The attendant", "The authorized entrant", "The entry supervisor", "The OSHA compliance officer"], a: 2, explain: "The entry supervisor is responsible for reviewing and signing the permit, authorizing entry into the PRCS.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "The attendant's role during confined space entry is to:", options: ["Enter to assist workers if needed", "Remain outside and monitor entrants and conditions", "Test the atmosphere inside the space", "Authorize entry if the supervisor is unavailable"], a: 1, explain: "The attendant must remain outside the PRCS, continuously track entrants, monitor conditions, and communicate with entrants. The attendant must NEVER enter the space to rescue.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "What must the attendant do if a rescue is needed?", options: ["Enter the space to rescue the worker", "Call trained rescue personnel — never enter the space", "Wait for the entry supervisor to decide", "Attempt rescue with other available workers"], a: 1, explain: "The attendant must NEVER enter the PRCS to perform a rescue. They must summon trained rescue personnel immediately.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "A retrieval system is required for confined space entry to:", options: ["Monitor atmospheric conditions", "Enable non-entry rescue of entrants", "Mark the entry point", "Measure the depth of the space"], a: 1, explain: "A retrieval system (typically a harness and retrieval line) allows the attendant to extract an entrant without entering the space.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "For vertical confined space entry, the retrieval system typically includes:", options: ["A ladder with safety cage", "A tripod and mechanical retrieval device", "A rope tied to a vehicle", "A portable scaffold"], a: 1, explain: "Vertical entries require a tripod or equivalent anchorage with a mechanical advantage retrieval device to extract entrants safely.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "A permit-required confined space may be reclassified as a non-permit space when:", options: ["The entry supervisor decides it is safe", "All serious hazards have been eliminated", "The atmosphere has been tested once and found acceptable", "The space has been in use for more than one shift"], a: 1, explain: "A PRCS may only be reclassified as non-permit when ALL actual and potential serious hazards have been completely eliminated.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Which of the following is an example of a permit-required confined space in construction?", options: ["A storage trailer", "A sewer manhole with potential for hazardous atmosphere", "A portable toilet", "A construction office"], a: 1, explain: "Sewer manholes commonly contain oxygen-deficient or toxic atmospheres, making them classic permit-required confined spaces.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Forced-air ventilation in a confined space must be:", options: ["Intermittent to conserve power", "Continuous throughout the entry", "Used only when the atmosphere tests fail", "Oxygen-based to enrich the atmosphere"], a: 1, explain: "Forced-air ventilation must run continuously during the entire entry operation to maintain safe atmospheric conditions.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Which gas must NEVER be used to ventilate a confined space?", options: ["Nitrogen", "Compressed air", "Oxygen", "Carbon dioxide"], a: 2, explain: "Pure oxygen must never be used to ventilate a confined space because it creates an oxygen-enriched atmosphere that dramatically increases fire and explosion risk.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Before entry into a PRCS begins, an emergency rescue plan must be:", options: ["Submitted to OSHA for approval", "Developed and in place before the first entry", "Posted at the nearest emergency room", "Filed with local fire department only"], a: 1, explain: "An emergency rescue plan must be developed and communicated before any entry into a permit-required confined space begins.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Hot work performed inside a confined space requires:", options: ["Only a hot work permit", "Additional permits, continuous air monitoring, and extra fire protection", "Only increased ventilation", "No additional requirements beyond standard hot work rules"], a: 1, explain: "Hot work in confined spaces requires additional permits, continuous atmospheric monitoring, enhanced ventilation, and fire protection beyond normal hot work requirements.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Which of the following would convert a permit-required space to a non-permit space?", options: ["Completing atmospheric testing before entry", "Eliminating all hazards that made the space permit-required", "Posting a warning sign at the entry point", "Limiting entry to experienced workers"], a: 1, explain: "Only complete elimination of all hazards that made the space permit-required can allow reclassification to a non-permit space.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Atmospheric conditions inside a confined space must be tested:", options: ["Only before initial entry", "Before entry and continuously or periodically during entry", "Once per shift by the entry supervisor", "Only when the attendant suspects a problem"], a: 1, explain: "Atmospheric testing is required before entry AND must continue (continuously or periodically) throughout the entry operation.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "What type of atmosphere represents an IDLH condition?", options: ["Any oxygen concentration below 20.9%", "A concentration of a toxic or flammable substance that poses an immediate threat to life or health", "Any atmosphere that smells unusual", "An oxygen level above 21%"], a: 1, explain: "IDLH conditions include toxic or flammable gas concentrations that are immediately dangerous to life or health, requiring immediate evacuation.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Which of the following is NOT a typical role in a permit-required confined space entry?", options: ["Entry supervisor", "Authorized entrant", "Safety watcher", "Attendant"], a: 2, explain: "The three recognized roles in PRCS entry are: Entry Supervisor, Authorized Entrant, and Attendant. 'Safety watcher' is not an OSHA-defined role.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Which of the following is an engulfment hazard in a confined space?", options: ["A slippery floor", "Grain, sand, water, or other material that could submerge a worker", "An uneven surface", "Exposed wiring"], a: 1, explain: "Engulfment hazards include any flowable material (grain, sand, liquid) that could surround and trap or submerge an entrant.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "The authorized entrant must exit immediately if:", options: ["They feel tired", "A prohibited condition is detected or the attendant orders evacuation", "The ventilation equipment makes noise", "Their shift ends"], a: 1, explain: "Authorized entrants must exit immediately if prohibited conditions (e.g., IDLH atmosphere) are detected or the attendant orders evacuation.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "The entry supervisor must verify which of the following before signing the entry permit?", options: ["That all workers have read the permit", "That all permit conditions (testing, equipment, rescue) are met", "That the permit fee has been paid", "That OSHA has been notified"], a: 1, explain: "The entry supervisor must verify all conditions on the permit are satisfied — atmospheric testing complete, rescue plan in place, equipment ready — before authorizing entry.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Which of the following best describes a non-permit confined space?", options: ["A space that is less than 4 feet deep", "A confined space with no actual or potential serious hazards", "A space where OSHA permits have expired", "Any space with good natural ventilation"], a: 1, explain: "A non-permit confined space is one that meets the definition of a confined space but contains no actual or potential serious hazards.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "What is the maximum safe oxygen concentration range for confined space entry?", options: ["15%–25%", "19.5%–23.5%", "20%–25%", "18%–22%"], a: 1, explain: "The acceptable oxygen range for confined space entry is 19.5% to 23.5% — below is deficiency, above is enrichment.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Which of the following is required on a confined space entry permit?", options: ["Names of entrants, entry supervisor, hazards, control measures, and rescue procedures", "Only the entrant's name and the date", "The supervisor's signature only", "A diagram of the space"], a: 0, explain: "Entry permits must include entrant names, supervisor name, hazards identified, controls in place, atmospheric test results, rescue procedures, and authorization signature.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "After work in a PRCS is complete, the entry permit must be:", options: ["Shredded for confidentiality", "Retained for at least 1 year for review", "Filed with the local fire marshal", "Returned to OSHA within 30 days"], a: 1, explain: "Completed entry permits must be retained for at least 1 year so they can be reviewed to improve the entry program.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Which atmospheric test must be performed FIRST in a confined space?", options: ["Carbon monoxide", "Flammable gas (LEL)", "Oxygen content", "Hydrogen sulfide"], a: 2, explain: "Oxygen must be tested first because sensor readings for flammable and toxic gases may be inaccurate in oxygen-deficient or oxygen-enriched atmospheres.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Workers who will enter a permit-required confined space must be trained as:", options: ["Rescue team members only", "Authorized entrants with knowledge of confined space hazards and emergency procedures", "General industry workers", "Equipment operators"], a: 1, explain: "All workers entering a PRCS must be trained and designated as authorized entrants, with knowledge of hazards, PPE, and emergency procedures.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'mc', q: "Carbon monoxide in a confined space is particularly dangerous because:", options: ["It has a distinctive odor that workers may ignore", "It is colorless and odorless and can reach IDLH levels without warning", "It is heavier than air and always settles at the bottom", "It reacts with oxygen to form an explosive mixture"], a: 1, explain: "CO is colorless, odorless, and tasteless — workers receive no sensory warning as concentrations rise to lethal levels.", moduleRef: 20, moduleName: "Confined Spaces" },

    // ── FIB (36-43)
    { type: 'fib', q: "The three roles in a permit-required confined space entry are Entry Supervisor, Authorized Entrant, and ___.", answer: "Attendant", accept: ["attendant"], explain: "The three OSHA-defined roles are Entry Supervisor, Authorized Entrant, and Attendant.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'fib', q: "Oxygen deficiency in a confined space is defined as an oxygen concentration below ___% .", answer: "19.5", accept: ["19.5%"], explain: "Below 19.5% oxygen, a confined space atmosphere is considered oxygen-deficient.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'fib', q: "Oxygen enrichment in a confined space occurs at concentrations above ___% .", answer: "23.5", accept: ["23.5%"], explain: "Oxygen concentrations above 23.5% create an oxygen-enriched atmosphere that significantly increases fire and explosion risk.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'fib', q: "Flammable gas concentrations in a confined space must be below ___% of the LEL before entry.", answer: "10", accept: ["ten", "10%"], explain: "Entry is permitted only when flammable gas concentration is below 10% of the Lower Explosive Limit.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'fib', q: "The correct order of atmospheric testing in a confined space is oxygen, flammable, and ___.", answer: "toxic", accept: ["toxics", "toxic contaminants"], explain: "Atmospheric testing order: 1) Oxygen, 2) Flammable gases, 3) Toxic contaminants.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'fib', q: "The ___ must remain outside a permit-required confined space and never enter to perform a rescue.", answer: "attendant", accept: ["Attendant"], explain: "The attendant's duty station is outside the PRCS; they must never enter — even to rescue an entrant.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'fib', q: "IDLH stands for Immediately Dangerous to ___ or Health.", answer: "Life", accept: ["life"], explain: "IDLH = Immediately Dangerous to Life or Health — conditions requiring immediate escape.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'fib', q: "Forced-air ventilation in confined spaces must be ___ — not turned off while workers are inside.", answer: "continuous", accept: ["constant", "continuously operated"], explain: "Continuous forced-air ventilation is mandatory throughout the entire confined space entry operation.", moduleRef: 20, moduleName: "Confined Spaces" },

    // ── SA (44-50)
    { type: 'sa', q: "Which of the following conditions make a confined space permit-required? (Select all that apply)", options: ["Hazardous atmosphere", "Engulfment potential", "Limited means of entry and exit", "Internal geometry that could trap an entrant"], answers: [0, 1, 3], explain: "Hazardous atmosphere, engulfment potential, and internal trapping geometry are all conditions that make a confined space permit-required. Limited entry/exit is part of the definition of any confined space but alone does not make it permit-required.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'sa', q: "Which of the following are responsibilities of the attendant during a confined space entry? (Select all that apply)", options: ["Remain outside the space", "Track the number of entrants", "Enter the space to assist when an entrant is in distress", "Order evacuation when prohibited conditions arise"], answers: [0, 1, 3], explain: "Attendants must remain outside, track entrants, and order evacuation. They must NEVER enter the space for any reason — rescue must be performed by trained rescue teams.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'sa', q: "Which of the following are required before entering a permit-required confined space? (Select all that apply)", options: ["Atmospheric testing in the correct order", "Entry permit signed by the entry supervisor", "Rescue plan established before entry begins", "OSHA verbal clearance obtained"], answers: [0, 1, 2], explain: "Atmospheric testing, a signed entry permit, and a pre-established rescue plan are all required before PRCS entry. OSHA verbal clearance is not a requirement.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'sa', q: "Which of the following are examples of permit-required confined spaces in construction? (Select all that apply)", options: ["Sewer manholes", "Underground utility vaults", "Construction storage trailers", "Tunnels under construction"], answers: [0, 1, 3], explain: "Sewer manholes, underground utility vaults, and tunnels are common PRCS examples. Construction trailers do not meet the confined space definition.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'sa', q: "Which of the following are correct statements about atmospheric testing in confined spaces? (Select all that apply)", options: ["Oxygen must be tested first", "Testing must continue during the entry, not just before", "Flammable gas must be tested before oxygen", "Toxic contaminants are tested last in the sequence"], answers: [0, 1, 3], explain: "Oxygen is tested first, testing is continuous, and toxics are tested last. Testing flammable gas before oxygen is incorrect — sensor accuracy depends on adequate oxygen levels.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'sa', q: "Which of the following are required elements of a confined space entry permit? (Select all that apply)", options: ["Names of authorized entrants and entry supervisor", "Atmospheric test results", "OSHA permit number", "Identified hazards and control measures"], answers: [0, 1, 3], explain: "Entry permits must include entrant/supervisor names, test results, and identified hazards and controls. OSHA does not issue permit numbers for confined space entry.", moduleRef: 20, moduleName: "Confined Spaces" },
    { type: 'sa', q: "Which of the following are correct practices for ventilating a confined space? (Select all that apply)", options: ["Use forced-air (mechanical) ventilation", "Ventilation must be continuous throughout entry", "Oxygen may be used to quickly enrich a deficient atmosphere", "Air intake for ventilation must be positioned to draw fresh outside air"], answers: [0, 1, 3], explain: "Forced-air continuous ventilation drawing fresh outside air is required. Using oxygen to ventilate is strictly prohibited because it creates a dangerously oxygen-enriched atmosphere.", moduleRef: 20, moduleName: "Confined Spaces" },
  ],
};
